                    Path file = it.next();
                    // Skip directories
                    if (Files.isDirectory(file)) {
                        continue;
                    }
                    Path fileName = file.getFileName();
                    if (fileName != null && matcher.matches(fileName)) {
                        matchingFiles.add(file.toString());
                    }
                }
            }

            return String.join("\n", matchingFiles);
        } catch (IOException e) {
            return "Error: " + e.getMessage();
        }
    }
}
